Bash(node --input-type=module << 'EOF'
// Does verify-payment.js guard against missing RAZORPAY_KEY_SECRET?
// Looking at the code: process.env.RAZORPAY_KEY_SECRET is used directly
// without a null-check, unlike create-order.js which has getRazorpay\(\) with explicit guard.

// In verify-payment.js line 61-63:
// const expectedHex = crypto.createHmac\('sha256', process.env.RAZORPAY_KEY_SECRET\).update\(body\).digest\('hex'\)
// If RAZORPAY_KEY_SECRET is undefined, this THROWS — which is an unhandled exception
// that will crash the serverless function with a 500, not a graceful error

// But what if the env var is set to empty string?
// An empty string key means HMAC is computed with no real secret
// An attacker who knows the formula can compute a valid signature with empty key

const emptyKeySecret = '';
import crypto from 'crypto';
const body = 'order_test123|pay_test456';
const expectedHex = crypto.createHmac\('sha256', emptyKeySecret\).update\(body\).digest\('hex'\);
console.log\('Signature with empty key:', expectedHex\);
console.log\('Attacker can forge signature if key is empty string: YES'\);
EOF)

Bash(node --input-type=module << 'EOF'
// Verify there's no rate limiting or brute-force protection
// Check: can an attacker call /api/create-order with 'new' plan 1000 times?
// Each call creates a real Razorpay order \(costs nothing until paid\)
// But it wastes Razorpay API quota and could enable enumeration

// Check: can /api/verify-payment be flooded with invalid signatures?
// The HMAC check is O\(1\) and cheap, but there's no lockout mechanism
// An attacker could try to brute-force a payment verification for any order_id
// \(though with 64-char hex HMAC, brute force is computationally infeasible\)

// More realistic: replay attack
// If the same valid signature is submitted twice:
// First call: inserts to MongoDB \(success\)
// Second call: duplicate key error \(11000\) — silently ignored, returns 200
// Result: user gets double confirmation emails but no double charge
// This is the CORRECT behavior but worth documenting

console.log\('Replay attack result: silently ignored \(correct — idempotent\)'\);
console.log\('Brute force signature: computationally infeasible \(256-bit HMAC\)'\);
console.log\('Rate limiting: ABSENT — no protection against order creation spam'\);
console.log\('DoS via order flood: possible \(creates orphaned Razorpay orders\)'\);
EOF)

